189ŌåÆ    if (subtasks?.length) {
190ŌåÆ      lines.push("\nSubtasks:");
191ŌåÆ      for (const s of subtasks) lines.push(`  - [${s.status}] ${s.title}`);
192ŌåÆ    }
193ŌåÆ
194ŌåÆ    const siblings = taskScope.sibling_tasks as Array<{ id: string; title: string; status: string }>;
195ŌåÆ    if (siblings?.length) {
196ŌåÆ      lines.push("\nSibling tasks:");
197ŌåÆ      for (const s of siblings) lines.push(`  - [${s.status}] ${s.title}`);
198ŌåÆ    }
199ŌåÆ    lines.push("");
200ŌåÆ  }
201ŌåÆ
202ŌåÆ  // Decisions
