208ŌåÆ        lines.push(`  - ${d.summary}${d.rationale ? ` ŌĆö ${d.rationale}` : ""}`);
209ŌåÆ      }
210ŌåÆ      lines.push("");
211ŌåÆ    }
212ŌåÆ
