214ŌåÆ      lines.push("## Confirmed Decisions (follow these)");
215ŌåÆ      for (const d of decisions.confirmed as Array<{ summary: string }>) {
216ŌåÆ        lines.push(`  - ${d.summary}`);
217ŌåÆ      }
218ŌåÆ      lines.push("");
219ŌåÆ    }
220ŌåÆ
221ŌåÆ    if (decisions.provisional.length > 0) {
