246ŌåÆ    }
247ŌåÆ    lines.push("");
248ŌåÆ  }
249ŌåÆ
250ŌåÆ  // Recent changes
251ŌåÆ  const changes = p.recent_changes as Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> | undefined;
252ŌåÆ  if (changes?.length) {
253ŌåÆ    lines.push("## Recent Changes");
254ŌåÆ    for (const c of changes) {
