408ŌåÆ/** Compute and apply subtask rollup on a parent task */
409ŌåÆasync function computeSubtaskRollup(
410ŌåÆ  surreal: Surreal,
411ŌåÆ  parentRecord: RecordId<"task", string>,
412ŌåÆ): Promise<string> {
413ŌåÆ  const [subtaskRows] = await surreal
414ŌåÆ    .query<[SubtaskRow[]]>(
415ŌåÆ      `SELECT id, title, status
416ŌåÆ       FROM task
417ŌåÆ       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
418ŌåÆ      { parent: parentRecord },
419ŌåÆ    )
420ŌåÆ    .collect<[SubtaskRow[]]>();
421ŌåÆ
422ŌåÆ  if (subtaskRows.length === 0) return "unknown";
423ŌåÆ
424ŌåÆ  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
425ŌåÆ  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
426ŌåÆ  const anyInProgress = subtaskRows.some((s) => s.status === "in_progress");
427ŌåÆ  const allTodo = subtaskRows.every((s) => s.status === "todo");
428ŌåÆ
429ŌåÆ  let derivedStatus: string;
430ŌåÆ
431ŌåÆ  if (allCompleted) derivedStatus = "completed";
432ŌåÆ  else if (anyBlocked && anyInProgress) derivedStatus = "in_progress";
433ŌåÆ  else if (anyBlocked) derivedStatus = "blocked";
434ŌåÆ  else if (anyInProgress) derivedStatus = "in_progress";
435ŌåÆ  else if (allTodo) derivedStatus = "todo";
436ŌåÆ  else derivedStatus = "in_progress";
437ŌåÆ
438ŌåÆ  await surreal.update(parentRecord).merge({
439ŌåÆ    status: derivedStatus,
440ŌåÆ    updated_at: new Date(),
441ŌåÆ  });
442ŌåÆ
443ŌåÆ  return derivedStatus;
444ŌåÆ}
