660ŌåÆ// ---------------------------------------------------------------------------
661ŌåÆ// Utility
662ŌåÆ// ---------------------------------------------------------------------------
663ŌåÆ
664ŌåÆfunction levenshteinSimilarity(a: string, b: string): number {
665ŌåÆ  if (a === b) return 1;
666ŌåÆ  const longer = a.length > b.length ? a : b;
667ŌåÆ  const shorter = a.length > b.length ? b : a;
668ŌåÆ  if (longer.length === 0) return 1;
669ŌåÆ
670ŌåÆ  const costs: number[] = [];
671ŌåÆ  for (let i = 0; i <= longer.length; i++) {
672ŌåÆ    let lastValue = i;
673ŌåÆ    for (let j = 0; j <= shorter.length; j++) {
674ŌåÆ      if (i === 0) {
675ŌåÆ        costs[j] = j;
676ŌåÆ      } else if (j > 0) {
677ŌåÆ        let newValue = costs[j - 1];
678ŌåÆ        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
679ŌåÆ          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
680ŌåÆ        }
681ŌåÆ        costs[j - 1] = lastValue;
682ŌåÆ        lastValue = newValue;
683ŌåÆ      }
684ŌåÆ    }
685ŌåÆ    if (i > 0) costs[shorter.length] = lastValue;
686ŌåÆ  }
687ŌåÆ
688ŌåÆ  return (longer.length - costs[shorter.length]) / longer.length;
689ŌåÆ}
