  if (questions?.length) {
    lines.push("## Open Questions");
    for (const q of questions) {
      lines.push(`  - [${q.status}] ${q.text}`);
    }
    lines.push("");
  }

  // Recent changes
  const changes = p.recent_changes as Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> | undefined;
  if (changes?.length) {
