    // Tier 2 ŌĆö Reason
    handleResolveDecision,
    handleCheckConstraints,
    // Tier 3 ŌĆö Write
    handleCreateProvisionalDecision,
    handleAskQuestion,
    handleUpdateTaskStatus,
    handleCreateSubtask,
    handleLogNote,
    // Lifecycle
    handleSessionStart,
    handleSessionEnd,
    handleLogCommit,
    handleCheckCommit,
  };
}

