 65ŌåÆ/** List active decisions for a project, optionally filtered by area/category */
 66ŌåÆexport async function listProjectDecisions(input: {
 67ŌåÆ  surreal: Surreal;
 68ŌåÆ  workspaceRecord: RecordId<"workspace", string>;
 69ŌåÆ  projectRecord: RecordId<"project", string>;
 70ŌåÆ  area?: string;
 71ŌåÆ}): Promise<{
 72ŌåÆ  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 73ŌåÆ  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 74ŌåÆ  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 75ŌåÆ}> {
 76ŌåÆ  const areaFilter = input.area
 77ŌåÆ    ? `AND category = $area`
 78ŌåÆ    : "";
 79ŌåÆ
 80ŌåÆ  const [rows] = await input.surreal
 81ŌåÆ    .query<[DecisionRow[]]>(
 82ŌåÆ      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 83ŌåÆ       FROM decision
 84ŌåÆ       WHERE workspace = $workspace
 85ŌåÆ         AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)
 86ŌåÆ         ${areaFilter}
 87ŌåÆ       ORDER BY created_at DESC LIMIT 50;`,
 88ŌåÆ      {
 89ŌåÆ        workspace: input.workspaceRecord,
 90ŌåÆ        project: input.projectRecord,
 91ŌåÆ        ...(input.area ? { area: input.area } : {}),
 92ŌåÆ      },
 93ŌåÆ    )
 94ŌåÆ    .collect<[DecisionRow[]]>();
 95ŌåÆ
 96ŌåÆ  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 97ŌåÆ  const confirmed: DecisionItem[] = [];
 98ŌåÆ  const provisional: DecisionItem[] = [];
 99ŌåÆ  const contested: DecisionItem[] = [];
100ŌåÆ
101ŌåÆ  for (const d of rows) {
102ŌåÆ    const item: DecisionItem = {
103ŌåÆ      id: toId(d.id),
104ŌåÆ      summary: d.summary,
105ŌåÆ      status: d.status,
106ŌåÆ      ...(d.rationale ? { rationale: d.rationale } : {}),
107ŌåÆ      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
108ŌåÆ      ...(d.category ? { category: d.category } : {}),
109ŌåÆ    };
110ŌåÆ
111ŌåÆ    if (d.status === "contested") contested.push(item);
112ŌåÆ    else if (d.status === "provisional" || d.status === "inferred") provisional.push(item);
113ŌåÆ    else if (d.status === "confirmed") confirmed.push(item);
114ŌåÆ  }
115ŌåÆ
116ŌåÆ  return { confirmed, provisional, contested };
117ŌåÆ}
