119ŌåÆ/** Get task dependency tree (recursive) */
120ŌåÆexport async function getTaskDependencyTree(input: {
121ŌåÆ  surreal: Surreal;
122ŌåÆ  taskRecord: RecordId<"task", string>;
123ŌåÆ}): Promise<{
124ŌåÆ  task: { id: string; title: string; status: string };
125ŌåÆ  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
126ŌåÆ  dependents: Array<{ id: string; title: string; status: string }>;
127ŌåÆ  subtasks: Array<{ id: string; title: string; status: string }>;
128ŌåÆ}> {
129ŌåÆ  const task = await input.surreal.select<TaskRow>(input.taskRecord);
130ŌåÆ  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
131ŌåÆ
132ŌåÆ  const query = `
133ŌåÆ    -- Tasks this task depends on
134ŌåÆ    SELECT id, title, status
135ŌåÆ    FROM task
136ŌåÆ    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
137ŌåÆ
138ŌåÆ    -- Tasks that depend on this task
139ŌåÆ    SELECT id, title, status
140ŌåÆ    FROM task
141ŌåÆ    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
142ŌåÆ
143ŌåÆ    -- Subtasks
144ŌåÆ    SELECT id, title, status
145ŌåÆ    FROM task
146ŌåÆ    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
147ŌåÆ    ORDER BY created_at ASC;
148ŌåÆ  `;
149ŌåÆ
150ŌåÆ  const results = await input.surreal
151ŌåÆ    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
152ŌåÆ    .collect<[DependencyRow[], DependencyRow[], SubtaskRow[]]>();
153ŌåÆ
154ŌåÆ  const [deps, dependents, subtasks] = results;
155ŌåÆ
156ŌåÆ  return {
157ŌåÆ    task: { id: toId(task.id), title: task.title, status: task.status },
158ŌåÆ    dependencies: deps.map((d) => ({
159ŌåÆ      id: toId(d.id),
160ŌåÆ      title: d.title,
161ŌåÆ      status: d.status,
162ŌåÆ      resolved: d.status === "done" || d.status === "completed",
163ŌåÆ    })),
164ŌåÆ    dependents: dependents.map((d) => ({ id: toId(d.id), title: d.title, status: d.status })),
165ŌåÆ    subtasks: subtasks.map((s) => ({ id: toId(s.id), title: s.title, status: s.status })),
