169ŌåÆ/** List architecture constraints for a project */
170ŌåÆexport async function listProjectConstraints(input: {
171ŌåÆ  surreal: Surreal;
172ŌåÆ  workspaceRecord: RecordId<"workspace", string>;
173ŌåÆ  projectRecord: RecordId<"project", string>;
174ŌåÆ  area?: string;
175ŌåÆ}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
176ŌåÆ  // Constraints come from two sources:
177ŌåÆ  // 1. Decisions marked as confirmed/contested (hard constraints)
178ŌåÆ  // 2. Observations with severity "conflict" or "warning"
179ŌåÆ
180ŌåÆ  const areaFilter = input.area ? `AND category = $area` : "";
181ŌåÆ
182ŌåÆ  const query = `
183ŌåÆ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
184ŌåÆ
185ŌåÆ    SELECT summary AS text, "decision" AS source_type, status, id
186ŌåÆ    FROM decision
187ŌåÆ    WHERE workspace = $workspace
188ŌåÆ      AND id IN $project_entity_ids
189ŌåÆ      AND status IN ["confirmed", "contested"]
190ŌåÆ      ${areaFilter}
191ŌåÆ    ORDER BY created_at DESC LIMIT 30;
192ŌåÆ
193ŌåÆ    SELECT text, "observation" AS source_type, severity, id
194ŌåÆ    FROM observation
195ŌåÆ    WHERE workspace = $workspace
196ŌåÆ      AND status IN ["open", "acknowledged"]
197ŌåÆ      AND severity IN ["conflict", "warning"]
198ŌåÆ    ORDER BY created_at DESC LIMIT 20;
199ŌåÆ  `;
200ŌåÆ
201ŌåÆ  const results = await input.surreal
202ŌåÆ    .query<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
203ŌåÆ      query,
204ŌåÆ      {
205ŌåÆ        workspace: input.workspaceRecord,
206ŌåÆ        project: input.projectRecord,
207ŌåÆ        ...(input.area ? { area: input.area } : {}),
208ŌåÆ      },
209ŌåÆ    )
210ŌåÆ    .collect<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
211ŌåÆ
212ŌåÆ  const [, decisionRows, observationRows] = results;
213ŌåÆ
214ŌåÆ  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
215ŌåÆ
216ŌåÆ  for (const d of decisionRows) {
217ŌåÆ    constraints.push({
218ŌåÆ      text: d.text,
219ŌåÆ      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
220ŌåÆ      severity: d.status === "contested" ? "hard" : "hard",
221ŌåÆ    });
222ŌåÆ  }
223ŌåÆ
224ŌåÆ  for (const o of observationRows) {
225ŌåÆ    constraints.push({
226ŌåÆ      text: o.text,
227ŌåÆ      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
228ŌåÆ      severity: o.severity === "conflict" ? "hard" : "soft",
229ŌåÆ    });
230ŌåÆ  }
231ŌåÆ
232ŌåÆ  return constraints;
233ŌåÆ}
234ŌåÆ
235ŌåÆ/** List recent changes since a timestamp */
236ŌåÆexport async function listRecentChanges(input: {
237ŌåÆ  surreal: Surreal;
238ŌåÆ  workspaceRecord: RecordId<"workspace", string>;
239ŌåÆ  projectRecord?: RecordId<"project", string>;
240ŌåÆ  since: string;
241ŌåÆ}): Promise<Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>> {
242ŌåÆ  const sinceDate = new Date(input.since);
243ŌåÆ
244ŌåÆ  const projectFilter = input.projectRecord
245ŌåÆ    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
246ŌåÆ    : "";
247ŌåÆ
248ŌåÆ  const query = `
249ŌåÆ    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
250ŌåÆ    FROM decision
251ŌåÆ    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
252ŌåÆ    ORDER BY updated_at DESC LIMIT 20;
253ŌåÆ
254ŌåÆ    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
255ŌåÆ    FROM task
256ŌåÆ    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
257ŌåÆ    ORDER BY updated_at DESC LIMIT 20;
258ŌåÆ
259ŌåÆ    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
260ŌåÆ    FROM question
261ŌåÆ    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
262ŌåÆ    ORDER BY updated_at DESC LIMIT 20;
263ŌåÆ
264ŌåÆ    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
265ŌåÆ  `;
266ŌåÆ
267ŌåÆ  const results = await input.surreal
268ŌåÆ    .query<[null, null, null, EntityChangeRow[]]>(query, {
269ŌåÆ      workspace: input.workspaceRecord,
270ŌåÆ      since: sinceDate,
271ŌåÆ      ...(input.projectRecord ? { project: input.projectRecord } : {}),
272ŌåÆ    })
273ŌåÆ    .collect<[null, null, null, EntityChangeRow[]]>();
274ŌåÆ
275ŌåÆ  return (results[3] ?? []).map((r) => ({
276ŌåÆ    entity_type: r.entity_type,
277ŌåÆ    entity_name: r.entity_name,
278ŌåÆ    change_type: r.change_type,
279ŌåÆ    changed_at: toIso(r.changed_at),
280ŌåÆ  }));
281ŌåÆ}
282ŌåÆ
283ŌåÆ/** Create a subtask with semantic dedup */
284ŌåÆexport async function createSubtask(input: {
285ŌåÆ  surreal: Surreal;
286ŌåÆ  parentTaskRecord: RecordId<"task", string>;
287ŌåÆ  title: string;
288ŌåÆ  workspaceRecord: RecordId<"workspace", string>;
289ŌåÆ  category?: string;
290ŌåÆ  rationale?: string;
291ŌåÆ}): Promise<{ task_id: string; parent_task_id: string; already_existed: boolean }> {
292ŌåÆ  // Check for existing similar subtasks (semantic dedup by title)
293ŌåÆ  const normalizedTitle = input.title.toLowerCase().trim();
294ŌåÆ
295ŌåÆ  const [existingRows] = await input.surreal
296ŌåÆ    .query<[SubtaskRow[]]>(
297ŌåÆ      `SELECT id, title, status
298ŌåÆ       FROM task
299ŌåÆ       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent)
300ŌåÆ       ORDER BY created_at ASC;`,
301ŌåÆ      { parent: input.parentTaskRecord },
302ŌåÆ    )
303ŌåÆ    .collect<[SubtaskRow[]]>();
304ŌåÆ
305ŌåÆ  // Simple dedup: check if any existing subtask title is very similar
306ŌåÆ  for (const existing of existingRows) {
307ŌåÆ    const existingNormalized = existing.title.toLowerCase().trim();
308ŌåÆ    if (existingNormalized === normalizedTitle || levenshteinSimilarity(existingNormalized, normalizedTitle) > 0.85) {
309ŌåÆ      return {
310ŌåÆ        task_id: toId(existing.id),
311ŌåÆ        parent_task_id: toId(input.parentTaskRecord),
312ŌåÆ        already_existed: true,
313ŌåÆ      };
314ŌåÆ    }
315ŌåÆ  }
316ŌåÆ
317ŌåÆ  // Get parent task's category if not specified
318ŌåÆ  const parentTask = await input.surreal.select<TaskRow>(input.parentTaskRecord);
319ŌåÆ  if (!parentTask) throw new Error(`parent task not found: ${input.parentTaskRecord.id}`);
320ŌåÆ
321ŌåÆ  const now = new Date();
322ŌåÆ  const taskRecord = new RecordId("task", randomUUID());
323ŌåÆ
324ŌåÆ  await input.surreal.create(taskRecord).content({
325ŌåÆ    title: input.title,
326ŌåÆ    status: "todo",
327ŌåÆ    created_at: now,
328ŌåÆ    updated_at: now,
329ŌåÆ    workspace: input.workspaceRecord,
330ŌåÆ    ...(input.category ? { category: input.category } : parentTask.category ? { category: parentTask.category } : {}),
331ŌåÆ    ...(input.rationale ? { description: input.rationale } : {}),
332ŌåÆ  });
333ŌåÆ
334ŌåÆ  // Create subtask_of edge
335ŌåÆ  await input.surreal
336ŌåÆ    .relate(taskRecord, new RecordId("subtask_of", randomUUID()), input.parentTaskRecord, {
337ŌåÆ      added_at: now,
338ŌåÆ    })
339ŌåÆ    .output("after");
340ŌåÆ
341ŌåÆ  // Copy belongs_to edges from parent (inherit project/feature)
342ŌåÆ  const [parentBelongsTo] = await input.surreal
343ŌåÆ    .query<[Array<{ out: RecordId }>]>(
344ŌåÆ      "SELECT out FROM belongs_to WHERE `in` = $parent;",
345ŌåÆ      { parent: input.parentTaskRecord },
346ŌåÆ    )
347ŌåÆ    .collect<[Array<{ out: RecordId }>]>();
348ŌåÆ
349ŌåÆ  for (const edge of parentBelongsTo) {
350ŌåÆ    await input.surreal
351ŌåÆ      .relate(taskRecord, new RecordId("belongs_to", randomUUID()), edge.out, {
352ŌåÆ        added_at: now,
353ŌåÆ      })
354ŌåÆ      .output("after");
355ŌåÆ  }
356ŌåÆ
357ŌåÆ  return {
358ŌåÆ    task_id: toId(taskRecord),
359ŌåÆ    parent_task_id: toId(input.parentTaskRecord),
360ŌåÆ    already_existed: false,
361ŌåÆ  };
362ŌåÆ}
363ŌåÆ
364ŌåÆ/** Update task status with subtask rollup */
365ŌåÆexport async function updateTaskStatus(input: {
366ŌåÆ  surreal: Surreal;
367ŌåÆ  taskRecord: RecordId<"task", string>;
368ŌåÆ  status: string;
369ŌåÆ  notes?: string;
370ŌåÆ}): Promise<{ task_id: string; status: string; parent_status?: string }> {
371ŌåÆ  const now = new Date();
372ŌåÆ
373ŌåÆ  await input.surreal.update(input.taskRecord).merge({
374ŌåÆ    status: input.status,
375ŌåÆ    updated_at: now,
376ŌåÆ  });
377ŌåÆ
378ŌåÆ  if (input.notes) {
379ŌåÆ    // Append note to description_entries
380ŌåÆ    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
381ŌåÆ    const entries = task?.description_entries ?? [];
382ŌåÆ    entries.push({ text: input.notes, created_at: now });
383ŌåÆ    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
384ŌåÆ  }
385ŌåÆ
386ŌåÆ  // Check if this task has a parent (subtask_of) and compute rollup
387ŌåÆ  const [parentRows] = await input.surreal
388ŌåÆ    .query<[Array<{ out: RecordId<"task", string> }>]>(
389ŌåÆ      "SELECT out FROM subtask_of WHERE `in` = $task LIMIT 1;",
390ŌåÆ      { task: input.taskRecord },
391ŌåÆ    )
392ŌåÆ    .collect<[Array<{ out: RecordId<"task", string> }>]>();
393ŌåÆ
394ŌåÆ  let parentStatus: string | undefined;
395ŌåÆ
396ŌåÆ  if (parentRows.length > 0) {
397ŌåÆ    const parentRecord = parentRows[0].out;
398ŌåÆ    parentStatus = await computeSubtaskRollup(input.surreal, parentRecord);
399ŌåÆ  }
400ŌåÆ
401ŌåÆ  return {
402ŌåÆ    task_id: toId(input.taskRecord),
403ŌåÆ    status: input.status,
404ŌåÆ    ...(parentStatus ? { parent_status: parentStatus } : {}),
405ŌåÆ  };
406ŌåÆ}
407ŌåÆ
408ŌåÆ/** Compute and apply subtask rollup on a parent task */
409ŌåÆasync function computeSubtaskRollup(
410ŌåÆ  surreal: Surreal,
411ŌåÆ  parentRecord: RecordId<"task", string>,
412ŌåÆ): Promise<string> {
413ŌåÆ  const [subtaskRows] = await surreal
414ŌåÆ    .query<[SubtaskRow[]]>(
415ŌåÆ      `SELECT id, title, status
416ŌåÆ       FROM task
417ŌåÆ       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
418ŌåÆ      { parent: parentRecord },
419ŌåÆ    )
420ŌåÆ    .collect<[SubtaskRow[]]>();
421ŌåÆ
422ŌåÆ  if (subtaskRows.length === 0) return "unknown";
423ŌåÆ
424ŌåÆ  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
425ŌåÆ  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
