668ŌåÆfunction levenshteinSimilarity(a: string, b: string): number {
669ŌåÆ  if (a === b) return 1;
670ŌåÆ  const longer = a.length > b.length ? a : b;
671ŌåÆ  const shorter = a.length > b.length ? b : a;
672ŌåÆ  if (longer.length === 0) return 1;
673ŌåÆ
674ŌåÆ  const costs: number[] = [];
675ŌåÆ  for (let i = 0; i <= longer.length; i++) {
676ŌåÆ    let lastValue = i;
677ŌåÆ    for (let j = 0; j <= shorter.length; j++) {
678ŌåÆ      if (i === 0) {
679ŌåÆ        costs[j] = j;
680ŌåÆ      } else if (j > 0) {
681ŌåÆ        let newValue = costs[j - 1];
682ŌåÆ        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
683ŌåÆ          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
684ŌåÆ        }
685ŌåÆ        costs[j - 1] = lastValue;
686ŌåÆ        lastValue = newValue;
687ŌåÆ      }
688ŌåÆ    }
689ŌåÆ    if (i > 0) costs[shorter.length] = lastValue;
690ŌåÆ  }
691ŌåÆ
692ŌåÆ  return (longer.length - costs[shorter.length]) / longer.length;
693ŌåÆ}
