 1ŌåÆimport { tool } from "ai";
 2ŌåÆimport { RecordId } from "surrealdb";
 3ŌåÆimport { z } from "zod";
 4ŌåÆimport { ENTITY_CATEGORIES } from "../../../shared/contracts";
 5ŌåÆimport { createEmbeddingVector } from "../../graph/embeddings";
 6ŌåÆimport { isEntityInWorkspace, parseRecordIdString } from "../../graph/queries";
 7ŌåÆimport { createObservation } from "../../observation/queries";
