11ŌåÆexport function createCreateObservationTool(deps: ChatToolDeps) {
12ŌåÆ  return tool({
13ŌåÆ    description:
14ŌåÆ      "Create an observation in the workspace graph. Use proactively when you notice cross-cutting concerns ŌĆö risks, conflicts, gaps, or notable facts ŌĆö even if the user didn't ask.",
15ŌåÆ    inputSchema: z.object({
16ŌåÆ      text: z.string().min(1).describe("Observation text"),
17ŌåÆ      severity: z
18ŌåÆ        .enum(["info", "warning", "conflict"])
19ŌåÆ        .describe(
20ŌåÆ          "info: awareness-level signals. warning: risks to address soon. conflict: contradictions needing human resolution.",
21ŌåÆ        ),
22ŌåÆ      category: z.enum(ENTITY_CATEGORIES).optional().describe("Optional observation category"),
23ŌåÆ      related_entity_id: z
24ŌåÆ        .string()
25ŌåÆ        .optional()
26ŌåÆ        .describe("Optional related entity id (project/feature/task/decision/question)"),
27ŌåÆ    }),
28ŌåÆ    execute: async (input, options) => {
29ŌåÆ      const context = requireToolContext(options);
30ŌåÆ
31ŌåÆ      const relatedRecord = input.related_entity_id
32ŌåÆ        ? parseRecordIdString(
33ŌåÆ            input.related_entity_id,
34ŌåÆ            ["project", "feature", "task", "decision", "question"],
35ŌåÆ          ) as RecordId<"project" | "feature" | "task" | "decision" | "question", string>
36ŌåÆ        : undefined;
37ŌåÆ
38ŌåÆ      if (relatedRecord) {
39ŌåÆ        const scoped = await isEntityInWorkspace(deps.surreal, context.workspaceRecord, relatedRecord);
40ŌåÆ        if (!scoped) {
41ŌåÆ          throw new Error("related entity is outside the current workspace scope");
42ŌåÆ        }
43ŌåÆ      }
44ŌåÆ
45ŌåÆ      const embedding = await createEmbeddingVector(deps.embeddingModel, input.text, deps.embeddingDimension);
46ŌåÆ      if (!embedding) {
47ŌåÆ        throw new Error("failed to create embedding for create_observation");
48ŌåÆ      }
49ŌåÆ
50ŌåÆ      const observationRecord = await createObservation({
51ŌåÆ        surreal: deps.surreal,
52ŌåÆ        workspaceRecord: context.workspaceRecord,
53ŌåÆ        text: input.text,
54ŌåÆ        severity: input.severity,
55ŌåÆ        ...(input.category ? { category: input.category } : {}),
56ŌåÆ        sourceAgent: context.actor,
57ŌåÆ        now: new Date(),
58ŌåÆ        sourceMessageRecord: context.currentMessageRecord,
59ŌåÆ        ...(relatedRecord ? { relatedRecord } : {}),
60ŌåÆ        embedding,
61ŌåÆ      });
62ŌåÆ
63ŌåÆ      return {
64ŌåÆ        observation_id: `observation:${observationRecord.id as string}`,
65ŌåÆ        severity: input.severity,
66ŌåÆ        status: "open",
67ŌåÆ      };
68ŌåÆ    },
69ŌåÆ  });
70ŌåÆ}
