 62ŌåÆfunction normalizeTokens(value: string): Set<string> {
 63ŌåÆ  return new Set(
 64ŌåÆ    value
 65ŌåÆ      .toLowerCase()
 66ŌåÆ      .replace(/[^a-z0-9\s]/g, " ")
