281ŌåÆ  /** POST /api/mcp/:workspaceId/decisions/resolve ŌĆö Infer decision from graph */
282ŌåÆ  async function handleResolveDecision(workspaceId: string, request: Request): Promise<Response> {
283ŌåÆ    const auth = await requireAuth(request, workspaceId);
284ŌåÆ    if (auth instanceof Response) return auth;
285ŌåÆ
286ŌåÆ    const body = await parseJsonBody<{
287ŌåÆ      question: string;
288ŌåÆ      options?: string[];
289ŌåÆ      context?: { project?: string; feature?: string };
290ŌåÆ    }>(request);
291ŌåÆ    if (body instanceof Response) return body;
292ŌåÆ    if (!body.question) return jsonError("question is required", 400);
293ŌåÆ
294ŌåÆ    // Embed the question and search for related decisions
295ŌåÆ    const queryEmbedding = await createEmbeddingVector(
296ŌåÆ      deps.embeddingModel,
297ŌåÆ      body.question,
298ŌåÆ      config.embeddingDimension,
299ŌåÆ    );
300ŌåÆ
301ŌåÆ    if (!queryEmbedding) {
302ŌåÆ      return jsonResponse({
303ŌåÆ        decision: undefined,
304ŌåÆ        confidence: 0,
305ŌåÆ        status: "unresolved",
306ŌåÆ        rationale: "Could not create embedding for question",
307ŌåÆ        sources: [],
308ŌåÆ      }, 200);
309ŌåÆ    }
310ŌåÆ
311ŌåÆ    const projectRecord = body.context?.project
312ŌåÆ      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
313ŌåÆ      : undefined;
314ŌåÆ
315ŌåÆ    const candidates = await searchEntitiesByEmbedding({
316ŌåÆ      surreal,
317ŌåÆ      workspaceRecord: auth.workspaceRecord,
318ŌåÆ      queryEmbedding,
319ŌåÆ      kinds: ["decision"],
320ŌåÆ      ...(projectRecord ? { projectRecord } : {}),
321ŌåÆ      limit: 10,
322ŌåÆ    });
323ŌåÆ
324ŌåÆ    // Check if any existing decision resolves the question
325ŌåÆ    const questionTokens = normalizeTokens(body.question);
326ŌåÆ    const relevant = candidates.filter((c) => {
327ŌåÆ      const tokens = normalizeTokens(c.name);
328ŌåÆ      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
329ŌåÆ    });
330ŌåÆ
331ŌåÆ    if (relevant.length > 0) {
332ŌåÆ      const best = relevant[0];
333ŌåÆ      return jsonResponse({
334ŌåÆ        decision: best.name,
335ŌåÆ        confidence: Number(best.score.toFixed(4)),
336ŌåÆ        status: best.status ?? "unknown",
337ŌåÆ        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
338ŌåÆ        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
339ŌåÆ      }, 200);
340ŌåÆ    }
341ŌåÆ
342ŌåÆ    return jsonResponse({
343ŌåÆ      decision: undefined,
344ŌåÆ      confidence: 0,
345ŌåÆ      status: "unresolved",
346ŌåÆ      rationale: "No existing decision found that resolves this question",
347ŌåÆ      sources: candidates.slice(0, 5).map((c) => ({
348ŌåÆ        id: `${c.kind}:${c.id}`,
349ŌåÆ        name: c.name,
350ŌåÆ        score: Number(c.score.toFixed(4)),
351ŌåÆ      })),
352ŌåÆ    }, 200);
353ŌåÆ  }
