355ŌåÆ  /** POST /api/mcp/:workspaceId/constraints/check ŌĆö Check proposed action */
356ŌåÆ  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
357ŌåÆ    const auth = await requireAuth(request, workspaceId);
358ŌåÆ    if (auth instanceof Response) return auth;
359ŌåÆ
360ŌåÆ    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
361ŌåÆ    if (body instanceof Response) return body;
362ŌåÆ    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
363ŌåÆ
364ŌåÆ    const queryEmbedding = await createEmbeddingVector(
365ŌåÆ      deps.embeddingModel,
366ŌåÆ      body.proposed_action,
367ŌåÆ      config.embeddingDimension,
368ŌåÆ    );
369ŌåÆ
370ŌåÆ    if (!queryEmbedding) {
371ŌåÆ      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
372ŌåÆ    }
373ŌåÆ
374ŌåÆ    const projectRecord = body.project
375ŌåÆ      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
376ŌåÆ      : undefined;
377ŌåÆ
378ŌåÆ    const candidates = await listDecisionConstraintCandidates({
379ŌåÆ      surreal,
380ŌåÆ      workspaceRecord: auth.workspaceRecord,
381ŌåÆ      queryEmbedding,
382ŌåÆ      ...(projectRecord ? { projectRecord } : {}),
383ŌåÆ      limit: 14,
384ŌåÆ    });
385ŌåÆ
386ŌåÆ    const actionTokens = normalizeTokens(body.proposed_action);
387ŌåÆ    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
388ŌåÆ    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
389ŌåÆ    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
390ŌåÆ
391ŌåÆ    for (const candidate of candidates) {
392ŌåÆ      const candidateTokens = normalizeTokens(candidate.name);
393ŌåÆ      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
394ŌåÆ      const status = candidate.status?.toLowerCase();
395ŌåÆ
396ŌåÆ      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
397ŌåÆ        hardConflicts.push({
398ŌåÆ          id: `${candidate.kind}:${candidate.id}`,
399ŌåÆ          name: candidate.name,
400ŌåÆ          score: Number(candidate.score.toFixed(4)),
401ŌåÆ          reason: `Decision is marked ${status}.`,
402ŌåÆ        });
403ŌåÆ        continue;
404ŌåÆ      }
405ŌåÆ
406ŌåÆ      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
407ŌåÆ        supporting.push({
408ŌåÆ          id: `${candidate.kind}:${candidate.id}`,
409ŌåÆ          name: candidate.name,
410ŌåÆ          score: Number(candidate.score.toFixed(4)),
411ŌåÆ          reason: "High-similarity decision aligns with proposed action.",
412ŌåÆ        });
413ŌåÆ        continue;
414ŌåÆ      }
415ŌåÆ
416ŌåÆ      if (candidate.score >= 0.72) {
417ŌåÆ        softTensions.push({
418ŌåÆ          id: `${candidate.kind}:${candidate.id}`,
419ŌåÆ          name: candidate.name,
420ŌåÆ          score: Number(candidate.score.toFixed(4)),
421ŌåÆ          reason: overlap
422ŌåÆ            ? "Related decision/question may require consistency checks."
423ŌåÆ            : "Semantically related context may be affected.",
424ŌåÆ        });
425ŌåÆ      }
426ŌåÆ    }
427ŌåÆ
428ŌåÆ    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
429ŌåÆ  }
