101ŌåÆexport async function listWorkspaceOpenObservations(input: {
102ŌåÆ  surreal: Surreal;
103ŌåÆ  workspaceRecord: RecordId<"workspace", string>;
104ŌåÆ  limit: number;
105ŌåÆ}): Promise<ObservationSummary[]> {
106ŌåÆ  const [rows] = await input.surreal
107ŌåÆ    .query<[
108ŌåÆ      Array<{
109ŌåÆ        id: ObservationRecord;
110ŌåÆ        text: string;
111ŌåÆ        severity: ObservationSeverity;
112ŌåÆ        status: ObservationStatus;
113ŌåÆ        category?: EntityCategory;
114ŌåÆ        source_agent: string;
115ŌåÆ        created_at: string | Date;
116ŌåÆ      }>,
117ŌåÆ    ]>(
118ŌåÆ      [
119ŌåÆ        "SELECT id, text, severity, status, category, source_agent, created_at",
120ŌåÆ        "FROM observation",
121ŌåÆ        "WHERE workspace = $workspace",
122ŌåÆ        "AND status IN ['open', 'acknowledged']",
