  1ŌåÆimport { RecordId, type Surreal } from "surrealdb";
  2ŌåÆimport type {
  3ŌåÆ  ContextPacket,
  4ŌåÆ  DecisionContext,
  5ŌåÆ  TaskContext,
  6ŌåÆ  QuestionContext,
  7ŌåÆ  ObservationContext,
  8ŌåÆ  TaskScopeContext,
  9ŌåÆ  RecentChangeContext,
 10ŌåÆ} from "./types";
 11ŌåÆ
 12ŌåÆtype ProjectRow = {
 13ŌåÆ  id: RecordId<"project", string>;
 14ŌåÆ  name: string;
 15ŌåÆ  status: string;
 16ŌåÆ  description?: string;
 17ŌåÆ};
 18ŌåÆ
 19ŌåÆtype DecisionRow = {
 20ŌåÆ  id: RecordId<"decision", string>;
 21ŌåÆ  summary: string;
 22ŌåÆ  status: string;
 23ŌåÆ  rationale?: string;
 24ŌåÆ  decided_at?: Date | string;
 25ŌåÆ  category?: string;
 26ŌåÆ  priority?: string;
 27ŌåÆ};
 28ŌåÆ
 29ŌåÆtype TaskRow = {
 30ŌåÆ  id: RecordId<"task", string>;
 31ŌåÆ  title: string;
 32ŌåÆ  status: string;
 33ŌåÆ  priority?: string;
 34ŌåÆ  category?: string;
 35ŌåÆ  description?: string;
 36ŌåÆ  source_session?: RecordId<"agent_session", string>;
 37ŌåÆ};
 38ŌåÆ
 39ŌåÆtype QuestionRow = {
 40ŌåÆ  id: RecordId<"question", string>;
 41ŌåÆ  text: string;
 42ŌåÆ  status: string;
 43ŌåÆ  context?: string;
 44ŌåÆ  priority?: string;
 45ŌåÆ};
 46ŌåÆ
 47ŌåÆtype ObservationRow = {
 48ŌåÆ  id: RecordId<"observation", string>;
 49ŌåÆ  text: string;
 50ŌåÆ  severity: string;
 51ŌåÆ  status: string;
 52ŌåÆ  category?: string;
 53ŌåÆ  observation_type?: string;
 54ŌåÆ};
 55ŌåÆ
 56ŌåÆtype AgentSessionRow = {
 57ŌåÆ  id: RecordId<"agent_session", string>;
 58ŌåÆ  agent: string;
 59ŌåÆ  ended_at?: Date | string;
 60ŌåÆ  summary?: string;
 61ŌåÆ};
 62ŌåÆ
 63ŌåÆtype SubtaskRow = {
 64ŌåÆ  id: RecordId<"task", string>;
 65ŌåÆ  title: string;
 66ŌåÆ  status: string;
 67ŌåÆ};
 68ŌåÆ
 69ŌåÆtype FeatureRow = {
 70ŌåÆ  id: RecordId<"feature", string>;
 71ŌåÆ  name: string;
 72ŌåÆ  description?: string;
 73ŌåÆ};
 74ŌåÆ
 75ŌåÆtype DependencyRow = {
 76ŌåÆ  id: RecordId<"task", string>;
 77ŌåÆ  title: string;
 78ŌåÆ  status: string;
 79ŌåÆ};
 80ŌåÆ
 81ŌåÆfunction toId(record: RecordId<string, string>): string {
 82ŌåÆ  return `${record.table.name}:${record.id as string}`;
 83ŌåÆ}
 84ŌåÆ
 85ŌåÆfunction toIso(value: Date | string | undefined): string {
 86ŌåÆ  if (!value) return "";
 87ŌåÆ  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
 88ŌåÆ}
 89ŌåÆ
 90ŌåÆ/** Build a broad project context packet (all decisions, tasks, questions for a project) */
 91ŌåÆexport async function buildProjectContext(input: {
 92ŌåÆ  surreal: Surreal;
 93ŌåÆ  workspaceRecord: RecordId<"workspace", string>;
 94ŌåÆ  workspaceName: string;
 95ŌåÆ  projectRecord: RecordId<"project", string>;
 96ŌåÆ  taskId?: string;
 97ŌåÆ  since?: string;
 98ŌåÆ}): Promise<ContextPacket> {
 99ŌåÆ  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
100ŌåÆ
101ŌåÆ  // Load project details
102ŌåÆ  const project = await surreal.select<ProjectRow>(projectRecord);
103ŌåÆ  if (!project) {
104ŌåÆ    throw new Error(`project not found: ${projectRecord.id}`);
105ŌåÆ  }
106ŌåÆ
107ŌåÆ  // Load project-scoped entities in parallel
108ŌåÆ  const projectEntitiesQuery = `
109ŌåÆ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
110ŌåÆ
111ŌåÆ    SELECT id, summary, status, rationale, decided_at, category, priority
112ŌåÆ    FROM decision
113ŌåÆ    WHERE workspace = $workspace AND id IN $project_entity_ids
114ŌåÆ    ORDER BY created_at DESC LIMIT 50;
115ŌåÆ
116ŌåÆ    SELECT id, title, status, priority, category, description, source_session
117ŌåÆ    FROM task
118ŌåÆ    WHERE workspace = $workspace AND id IN $project_entity_ids
119ŌåÆ    ORDER BY created_at DESC LIMIT 50;
120ŌåÆ
121ŌåÆ    SELECT id, text, status, context, priority
122ŌåÆ    FROM question
123ŌåÆ    WHERE workspace = $workspace AND id IN $project_entity_ids
124ŌåÆ    ORDER BY created_at DESC LIMIT 30;
125ŌåÆ
126ŌåÆ    SELECT id, text, severity, status, category, observation_type
127ŌåÆ    FROM observation
128ŌåÆ    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
129ŌåÆ    ORDER BY created_at DESC LIMIT 20;
130ŌåÆ  `;
131ŌåÆ
132ŌåÆ  const results = await surreal
133ŌåÆ    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>(projectEntitiesQuery, {
134ŌåÆ      project: projectRecord,
135ŌåÆ      workspace: workspaceRecord,
136ŌåÆ    })
137ŌåÆ    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>();
138ŌåÆ
139ŌåÆ  const [, decisionRows, taskRows, questionRows, observationRows] = results;
140ŌåÆ
141ŌåÆ  // Categorize decisions by status
142ŌåÆ  const confirmed: DecisionContext[] = [];
143ŌåÆ  const provisional: DecisionContext[] = [];
144ŌåÆ  const contested: DecisionContext[] = [];
145ŌåÆ
146ŌåÆ  for (const d of decisionRows) {
147ŌåÆ    const ctx: DecisionContext = {
148ŌåÆ      id: toId(d.id),
149ŌåÆ      summary: d.summary,
150ŌåÆ      status: d.status,
151ŌåÆ      ...(d.rationale ? { rationale: d.rationale } : {}),
152ŌåÆ      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
153ŌåÆ      ...(d.category ? { category: d.category } : {}),
154ŌåÆ      ...(d.priority ? { priority: d.priority } : {}),
155ŌåÆ    };
156ŌåÆ
157ŌåÆ    if (d.status === "contested") {
158ŌåÆ      contested.push(ctx);
159ŌåÆ    } else if (d.status === "provisional" || d.status === "inferred") {
160ŌåÆ      provisional.push(ctx);
161ŌåÆ    } else if (d.status === "confirmed") {
162ŌåÆ      confirmed.push(ctx);
163ŌåÆ    }
164ŌåÆ  }
165ŌåÆ
166ŌåÆ  // Map tasks
167ŌåÆ  const activeTasks: TaskContext[] = taskRows
168ŌåÆ    .filter((t) => t.status !== "done" && t.status !== "completed")
169ŌåÆ    .map((t) => ({
170ŌåÆ      id: toId(t.id),
171ŌåÆ      title: t.title,
172ŌåÆ      status: t.status,
173ŌåÆ      ...(t.priority ? { priority: t.priority } : {}),
174ŌåÆ      ...(t.category ? { category: t.category } : {}),
175ŌåÆ      ...(t.source_session ? { source_session: toId(t.source_session) } : {}),
176ŌåÆ    }));
177ŌåÆ
178ŌåÆ  // Map questions
179ŌåÆ  const openQuestions: QuestionContext[] = questionRows
180ŌåÆ    .filter((q) => q.status !== "answered" && q.status !== "resolved")
181ŌåÆ    .map((q) => ({
182ŌåÆ      id: toId(q.id),
183ŌåÆ      text: q.text,
184ŌåÆ      status: q.status,
185ŌåÆ      ...(q.context ? { context: q.context } : {}),
186ŌåÆ      ...(q.priority ? { priority: q.priority } : {}),
187ŌåÆ    }));
188ŌåÆ
189ŌåÆ  // Map observations
190ŌåÆ  const observations: ObservationContext[] = observationRows.map((o) => ({
191ŌåÆ    id: toId(o.id),
192ŌåÆ    text: o.text,
