 1ŌåÆ-- Add coding-agent-specific fields to observation table
 2ŌåÆ-- and observed_in relation for session tracking.
 3ŌåÆ
 4ŌåÆBEGIN TRANSACTION;
 5ŌåÆ
 6ŌåÆ-- Observation type: what kind of thing was observed (coding agent categories)
 7ŌåÆDEFINE FIELD observation_type ON observation TYPE option<string>
 8ŌåÆ  ASSERT $value IN ["contradiction", "duplication", "missing", "deprecated", "pattern", "anomaly"] OR $value IS NONE;
 9ŌåÆ
10ŌåÆ-- Link observation to the agent session that created it
11ŌåÆDEFINE FIELD source_session ON observation TYPE option<record<agent_session>>;
12ŌåÆ
13ŌåÆ-- Track observations logged during a session (populated at session end)
14ŌåÆDEFINE FIELD observations_logged ON agent_session TYPE option<array<record<observation>>>;
15ŌåÆ
