    siblingTasks = siblingRows.map((t) => ({
      id: toId(t.id),
      title: t.title,
      status: t.status,
      ...(t.source_session ? { source_session: toId(t.source_session) } : {}),
    }));
  }

  return {
    task: {
      id: toId(task.id),
      title: task.title,
      ...(task.description ? { description: task.description } : {}),
      status: task.status,
      ...(task.category ? { category: task.category } : {}),
